#include <bits/stdc++.h>
using namespace std;
struct Node {
    int data;
    Node* next;
    Node* prev;
    Node(int data) : data(data), next(nullptr), prev(nullptr) {}
};
struct DLL {
    Node* head;
    DLL() : head(nullptr) {}
    void append(int data) {
        if (!head) {
            head = new Node(data);
        } else {
            Node* cur = head;
            while (cur->next) {
                cur = cur->next;
            }
            Node* new_node = new Node(data);
            cur->next = new_node;
            new_node->prev = cur;
        }
    }
    void display(vector<int>& result) {
        Node* cur = head;
        while (cur) {
            result.push_back(cur->data);
            cur = cur->next;
        }
    }
};
Node* delete_occurrences(Node* head, int key) {
    Node* cur = head;
    while (cur) {
        Node* next_node = cur->next;
        if (cur->data == key) {
            if (cur->prev) {
                cur->prev->next = cur->next;
            } else {
                head = cur->next;
            }
            if (cur->next) {
                cur->next->prev = cur->prev;
            }
        }
        cur = next_node;
    }
    return head;
}
int main() {
    int n;
    cin >> n;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) cin >> nums[i];
    int target;
    cin >> target;
    DLL dll;
    for (int num : nums) {
        dll.append(num);
    }
    Node* head = dll.head;
    head = delete_occurrences(head, target);
    vector<int> result;
    Node* cur = head;
    while (cur) {
        result.push_back(cur->data);
        cur = cur->next;
    }
    cout << result.size() << endl;
    for (int num : result) {
        cout << num << endl;
    }
    return 0;
}
